// LESSON: JavaFX Dialog Files CSS - Reference Page 2.
// You will learn: Use dialogs, FileChooser, CSS, and resource paths in JavaFX.
import java.io.File;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import javafx.application.Application;
import javafx.scene.Scene;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.TextArea;
import javafx.scene.layout.VBox;
import javafx.stage.FileChooser;
import javafx.stage.Stage;

public class JavaFxDialogFilesCssReference extends Application {
  private TextArea textArea;

  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    textArea = new TextArea();
    Button alertButton = new Button("Show alert");
    alertButton.setOnAction(e -> showAlertExample());
    Button openButton = new Button("Open file");
    openButton.setOnAction(e -> openFileExample(stage));
    Button saveButton = new Button("Save");
    saveButton.setId("save-button");
    saveButton.getStyleClass().add("primary");
    VBox root = new VBox(8, alertButton, openButton, saveButton, textArea);
    Scene scene = new Scene(root, 420, 300);
    addCssExample(scene);
    stage.setScene(scene);
    stage.show();
  }

  private void showAlertExample() {
    Alert alert = new Alert(Alert.AlertType.INFORMATION);
    alert.setTitle("Saved");
    alert.setHeaderText(null);
    alert.setContentText("The text was saved.");
    alert.showAndWait();
  }

  private void openFileExample(Stage stage) {
    FileChooser chooser = new FileChooser();
    chooser.setTitle("Open text file");
    chooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("Text files", "*.txt"));
    File file = chooser.showOpenDialog(stage);
    if (file != null) {
      try {
        String text = new String(Files.readAllBytes(file.toPath()), StandardCharsets.UTF_8);
        textArea.setText(text);
      } catch (IOException ex) {
        textArea.setText("Could not read file: " + ex.getMessage());
      }
    }
  }

  private void addCssExample(Scene scene) {
    String css = getClass().getResource("/style.css").toExternalForm();
    scene.getStylesheets().add(css);
  }
}
